<template>
    <div class="popup_wrap">
        <div class="popup_content">
            <p class="popup_title">수정</p>
            <div class="input_area">
                <dl>
                    <dt>비밀번호</dt>
                    <dd>
                        <v-text-field v-model="PASSWORD" outlined hide-details class="white" :type="password" />
                    </dd>
                </dl>
                <dl>
                    <dt>비밀번호 확인</dt>
                    <dd>
                        <v-text-field v-model="PASSWORD_CONFIRM" outlined hide-details class="white" :type="password" />
                    </dd>
                </dl>
                <dl>
                    <dt>계정 권한</dt>
                    <dd>
                        <v-select
                            outlined
                            return-object
                            v-model="selectedUserType"
                            :items="userTypeList"
                            item-text="label"
                            item-value="value"
                            hide-details
                            class="white"
                            @change="validationCheck()"
                        />
                    </dd>
                </dl>
            </div>
            <div class="btn_area">
                <v-btn elevation="3" :disabled="!validation" color="primary" @click="doSave"> 저장 </v-btn>
                <v-btn outlined plain elevation="3" @click="popupCloseNo">취소</v-btn>
            </div>
        </div>
        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>
<script>
import * as JsonUtil from "@/common/JsonUtil";
import * as LogUtil from "@/common/LogUtil";
import * as User from "@/rest/User";

import AlertModal from '@/components/modal/AlertModal'

export default {
  components: {
    AlertModal
  },
  data: () => ({
    alertModalParams: { isOpened: false, title: '', message: ''},

    PASSWORD: null,
    PASSWORD_CONFIRM: null,
    selectedUserType: null,

    password: 'Password',
    validation: false,
    userTypeList: [
      { label : '시스템 관리자', value : 'S' },
      { label : '일반 사용자', value : 'U' }
    ]
  }),
  props: ['selectInfo'],
  mounted() {
    LogUtil.debug('AccountModify: mounted(): selectInfo=', this.selectInfo);      
    this.selectedUserType = JsonUtil.getObjectByValue(this.userTypeList, 'value', this.selectInfo.USER_TYPE)[0];
    LogUtil.debug('AccountModify: mounted(): selectedUserType=', this.selectedUserType);
  },
  updated() {
    this.validationCheck();
  },
  methods: {
    showAlertModal(msg) {
      this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
    },
    popupCloseNo() {
      this.$emit('popupCloseNo', false);
    },
    validationCheck() {
      if (this.PASSWORD !== null && this.PASSWORD === this.PASSWORD_CONFIRM) {
        this.validation = this.PASSWORD && this.selectedUserType;
      } else {
        if(this.PASSWORD === null && this.PASSWORD_CONFIRM === null) {
          this.validation = true;
        } else {
          this.validation = false;
        }
      }
    },
    doSave() {
      LogUtil.debug('AccountModify: doSave(): this.PASSWORD=', this.PASSWORD);
      let model = {
        USER_ID: this.selectInfo.USER_ID,
        USER_TYPE: this.selectedUserType.value
      };

      if(this.PASSWORD != undefined && this.PASSWORD === this.PASSWORD_CONFIRM) {
        model.PASSWORD = this.PASSWORD;
      } 
      User.save(model).then(res => {
        if(res.data.RES_CODE>=0) {
          LogUtil.debug('AccountModify: doSave(): res.data.RES_CODE=', res.data.RES_CODE);
          this.$emit('popupCloseYes', false);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
    }
  },
};
</script>

<style lang="scss" scoped>
.popup_wrap {
    .popup_content {
        width: 600px;
        padding: 0 10px;
        .popup_title {
            @include centerAlign();
            height: 52px;
            border-bottom: 1px solid #ccc;
            font: {
                size: 20px;
                weight: 600;
            }
        }
        .input_area {
            padding: 27px 0 30px;
            border-bottom: 1px solid #ccc;
            dl {
                @include hCenterAlign();
                dt {
                    width: 230px;
                    padding-right: 10px;
                    font: {
                        size: 15px;
                        weight: 500;
                    }
                    text-align: right;
                }
                dd {
                    width: 250px;
                }
                & + dl {
                    margin-top: 29px;
                }
            }
        }
        .btn_area {
            @include centerAlign();
            width: 100%;
            button + button {
                margin-left: 14px;
            }
        }
    }
}
</style>
