import PagePath from '@/components/widget/PagePath';
import accountList from '@/data/accountList';
import AccountAddPopup from '@/components/popup/account/AccountAdd';
import AccountModifyPopup from '@/components/popup/account/AccountModify';
import DeleteConfirmPopup from '@/components/popup/common/DeleteConfirm';

import * as LogUtil from "@/common/LogUtil";
import * as User from "@/rest/User";

import AlertModal from '@/components/modal/AlertModal'

export default {
    components: {
      PagePath,
      AccountAddPopup,
      AccountModifyPopup,
      AlertModal,
      DeleteConfirmPopup,
    },
    data: () => ({
      alertModalParams: { isOpened: false, title: '', message: ''},

      dataList: [],
      selectInfo: {},
      isAddPopupOpen: false,
      isModifyPopupOpen: false,
      isDeletePopupOpen: false,
      headers: [
        { text: 'No', sortable: false },
        { text: '아이디', value: 'accountId', sortable: false },
        { text: '비밀번호', value: 'accountPw', sortable: false },
        { text: '계정 권한', value: 'access', sortable: false },
      ],
    }),
    beforeMount() {
      this.initDataList();
    },
    methods: {
      showAlertModal(msg) {
        this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
      },
      popupAddView(view) {
        this.isAddPopupOpen = view;

        if (!view) {
          this.selectInfo = {};
        }
      },
      onInsert() {
        this.isAddPopupOpen = false;
        this.initDataList();
      },
      onInsertCancel() {
        this.isAddPopupOpen = false;
      },
      popupModifyView(view) {
        this.isModifyPopupOpen = view;

        if (!view) {
          this.selectInfo = {};
        }
      }, 
      onModify() {
        this.isModifyPopupOpen = false;
        this.initDataList();
      },
      onModifyCancel() {
        this.isModifyPopupOpen = false;
      },     
      popupDeleteView(view) {
        this.isDeletePopupOpen = view;
        LogUtil.debug("popupDeleteView(): this.selectInfo=", this.selectInfo);
      },
      onDelete() {
        if(this.selectInfo.USER_ID !== undefined) {
          User.deleteOne({
            USER_ID: this.selectInfo.USER_ID
          }).then(res => {
            if(res.data.RES_CODE>=0) {
              LogUtil.debug("res.data.RES_CODE=", res.data.RES_CODE);
              this.selectInfo = {};
              this.isDeletePopupOpen = false;
              this.initDataList();
            } else {
              this.showAlertModal(res.data.RES_MSG);
            }
          }).catch(e => {
            LogUtil.error("error=", e);
            this.showAlertModal(e);
          }).finally(() => {
          });
        }
      },
      onDeleteCancel() {
        this.isDeletePopupOpen = false;
      },
      selectList(select) {
        if (this.selectInfo === select) this.selectInfo = {};
        else this.selectInfo = select;
      },
      initDataList() {
        let options = {
          conditions: [
            // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
          ],
          orderBys: [
            { name: 'LOGIN_ID', operator: 'asc'}
          ],
          paging: { pageNo: 1, pageSize: 100 }
        };
        
        User.listByCondition(options).then(res => {
          if(res.data.RES_CODE>=0) {
            this.dataList = res.data.ITEMS;
            LogUtil.debug("this.dataList=", this.dataList);
          } else {
            this.showAlertModal(res.data.RES_MSG);
          }
        }).catch(e => {
          LogUtil.error("error=", e);
          this.showAlertModal(e);
        }).finally(() => {
        });
      },
  },
};